import './App.css';
import './Bubbles.css';
import React, {useState, useEffect} from 'react';
import Guppy from "./img/guppySMOL-BLUE.png"


function Bubbles({page}) {
    var [bubbling, setBubbling] = useState(false)

    function createBubble () {
        const container = document.getElementById("bubblesContainer")
        const createElement = document.createElement('span')
        var size = Math.random() * 60;

        createElement.style.width = size + "px";
        createElement.style.height = size + "px";
        createElement.style.left = Math.random() * 10 +  "px";
        createElement.style.top = "50px";
        createElement.style.backgroundColor = "red";
        createElement.innerText = "";
        container.appendChild(createElement)
        console.log(createElement)

        setTimeout(() => {
            createElement.remove()
        }, 6000)

    }
    setInterval(createBubble, 300)


  return (
    <div id="bubblesContainer">
        {/* <svg height="100" width="100" xmlns="http://www.w3.org/2000/svg">
            <circle r="45" cx="50" cy="50" fill="transparent" stroke="red" stroke-width="10"/>
        </svg> */}
        <button onClick={createBubble()}>
            create bubble
        </button>



    </div>
  );
}

export default Bubbles;
